```python

class Array(terms.Term):

    def __init__(self, value, alias=None):
        super().__init__(alias=alias)
        self.value = value

    def fields(self):
        return []

    def value_to_sql(self, value):
        if isinstance(value, (list, set, tuple)):
            return self.array_to_sql(self.value)
        if isinstance(value, str):
            return '\'%s\'' % value.replace('\'', '\'\'')
        return str(value)

    def array_to_sql(self, array):
        return '[%s]' % ','.join(tuple(self.value_to_sql(v) for v in array))

    def get_sql(self, quote_char=None, **kwargs):
        return alias_sql(
            'ARRAY' + self.array_to_sql(self.value)
            if self.value else 'DEFAULT',
            self.alias,
            quote_char
        )

class ArrayComparator(enums.Comparator):
    contains = '@>'
    isContainedBy = '<@'
    overlap = '&&'

# examples:
